#\n# @lc app=leetcode id=3455 lang=python3\n#\n# [3455] Shortest Matching Substring\n#\n\n# @lc code=start\nclass Solution:\n    def shortestMatchingSubstring(self, s: str, p: str) -> int:\n        from bisect import bisect_left, bisect_right\n\n        parts = p.split('*')\n        A = parts[0]\n        B = parts[1]\n        C = parts[2]\n        la = len(A)\n        lb = len(B)\n        lc = len(C)\n        n = len(s)\n\n        def find_all_matches(pattern):\n            matches = []\n            start = 0\n            while True:\n                pos = s.find(pattern, start)\n                if pos == -1:\n                    break\n                matches.append(pos)\n                start = pos + 1\n            return matches\n\n        listA = find_all_matches(A) if la > 0 else []\n        listB = find_all_matches(B) if lb > 0 else []\n        listC = find_all_matches(C) if lc > 0 else []\n\n        def get_max_start(lt_pos, lst, length):\n            if length == 0:\n                return lt_pos if 0 <= lt_pos <= n else -1\n            if not lst:\n                return -1\n            idx = bisect_right(lst, lt_pos) - 1\n            return lst[idx] if idx >= 0 else -1\n\n        def get_min_start(ge_pos, lst, length):\n            if length == 0:\n                return ge_pos if ge_pos <= n else n + 1\n            if not lst:\n                return n + 1\n            idx = bisect_left(lst, ge_pos)\n            return lst[idx] if idx < len(lst) else n + 1\n\n        min_len = float('inf')\n        if lb > 0:\n            for ib in listB:\n                target_ia = ib - la\n                ia = get_max_start(target_ia, listA, la)\n                if ia < 0:\n                    continue\n                target_ic = ib + lb\n                ic = get_min_start(target_ic, listC, lc)\n                if ic > n:\n                    continue\n                curr_len = ic + lc - ia\n                if curr_len < min_len:\n                    min_len = curr_len\n        else:\n            for ib in range(n + 1):\n                target_ia = ib - la\n                ia = get_max_start(target_ia, listA, la)\n                if ia < 0:\n                    continue\n                target_ic = ib\n                ic = get_min_start(target_ic, listC, lc)\n                if ic > n:\n                    continue\n                curr_len = ic + lc - ia\n                if curr_len < min_len:\n                    min_len = curr_len\n        return -1 if min_len == float('inf') else min_len\n\n# @lc code=end